select * from nx_dis_route_plan
where nx_drp_distributer_id = #{disId}
  and nx_drp_status = #{status}
  and (
      nx_drp_route_date = #{routeDate}
      or (nx_drp_route_date is null and nx_drp_plan_date = #{routeDate})
  )
order by nx_drp_id desc
limit 1

select * from nx_dis_route_plan
where nx_drp_distributer_id = #{disId}
  and nx_drp_status = #{status}
  and nx_drp_dispatch_batch = #{dispatchBatch}
  and (
      nx_drp_route_date = #{routeDate}
      or (nx_drp_route_date is null and nx_drp_plan_date = #{routeDate})
  )
order by nx_drp_id desc
limit 1

select * from nx_dis_route_plan

    and nx_drp_distributer_id = #{disId}

        and (nx_drp_route_date = #{routeDate}
        or (nx_drp_route_date is null and nx_drp_plan_date = #{routeDate}))


        and nx_drp_plan_date = #{planDate}

    and nx_drp_status = #{status}

order by nx_drp_id desc

mapper.update:
update nx_dis_route_plan
set nx_drp_feasibility_status = #{nxDrpFeasibilityStatus}
where nx_drp_id = #{nxDrpId}

update nx_dis_route_plan
set nx_drp_dispatch_batch    = #{nxDrpDispatchBatch},
    nx_drp_batch_start_at    = #{nxDrpBatchStartAt},
    nx_drp_batch_end_at      = #{nxDrpBatchEndAt},
    nx_drp_default_depart_at = #{nxDrpDefaultDepartAt}
where nx_drp_id = #{nxDrpId}

update nx_dis_route_plan
set nx_drp_status = 'CANCELLED'
where nx_drp_distributer_id = #{disId}
  and nx_drp_status in ('DRAFT', 'SIMULATED')
  and (
      nx_drp_route_date = #{routeDate}
      or (nx_drp_route_date is null and nx_drp_plan_date = #{routeDate})
  )

update nx_dis_route_plan
set nx_drp_status = 'CANCELLED'
where nx_drp_distributer_id = #{disId}
  and nx_drp_status in ('CONFIRMED', 'ASSIGNED', 'READY')
  and (
      nx_drp_route_date = #{routeDate}
      or (nx_drp_route_date is null and nx_drp_plan_date = #{routeDate})
  )
